      }
    }
    SumNonNeg(x[1..]);

    assert 0 <= r - keep <= Sum(x[1..]);

    GreedyKeepValid(x[1..], r - keep);

    var tail := GreedyKeep(x[1..], r - keep);

    assert |gk| > 0;
    SumCons(gk);
    assert gk[0] == keep;
    assert gk[1..] == tail;

    forall i | 0 <= i < |x|
      ensures 0 <= gk[i] <= x[i]
    {
